1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	};
7	
8	export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
9	  if (items.length === 0) return PROCESSING_FEE;
10	  const basePremium = BASE_PREMIUMS[items[0].type] ?? 0;
11	  const adjustedPremium = basePremium + basePremium / 10;
12	  return adjustedPremium + PROCESSING_FEE;
13	};
14	
